firmware_template.header:
#ifndef SOUND_LEVEL_H
#define SOUND_LEVEL_H
#include <Arduino.h>
void sound_level_setup();
void sound_level_loop();
float sound_level_db();       // calibrated dB SPL
float sound_level_rms();      // raw RMS 0.0-1.0
bool  sound_level_clap();     // true if sudden spike detected
#endif

firmware_template.source:
#include "sound_level_monitor.h"
#include <driver/i2s.h>
#include <math.h>

#define MIC_WS  4
#define MIC_SCK 5
#define MIC_SD  7
#define SR      16000
#define FRAME   256

static float _db = 0, _rms = 0;
static float _prev_db = 0;
static bool _clap = false;

void sound_level_setup() {
    i2s_config_t cfg = {};
    cfg.mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_RX);
    cfg.sample_rate = SR;
    cfg.bits_per_sample = I2S_BITS_PER_SAMPLE_32BIT;
    cfg.channel_format = I2S_CHANNEL_FMT_ONLY_LEFT;
    cfg.communication_format = I2S_COMM_FORMAT_STAND_I2S;
    cfg.dma_buf_count = 4;
    cfg.dma_buf_len = FRAME;
    cfg.use_apll = true;
    i2s_driver_install(I2S_NUM_0, &cfg, 0, NULL);
    i2s_pin_config_t p = { .bck_io_num=MIC_SCK, .ws_io_num=MIC_WS, .data_out_num=-1, .data_in_num=MIC_SD };
    i2s_set_pin(I2S_NUM_0, &p);
    Serial.println("[spl] OK");
}

void sound_level_loop() {
    int32_t buf[FRAME];
    size_t rd = 0;
    i2s_read(I2S_NUM_0, buf, sizeof(buf), &rd, portMAX_DELAY);
    int n = rd / 4;
    if (n <= 0) return;
    double sum = 0;
    for (int i = 0; i < n; i++) {
        double s = (double)(buf[i] >> 8) / (double)0x800000;
        sum += s * s;
    }
    _rms = (float)sqrt(sum / n);
    _prev_db = _db;
    _db = (_rms > 0) ? 20.0f * log10f(_rms) + 94.0f : 0;
    _clap = (_db - _prev_db > 15.0f);
}

float sound_level_db()  { return _db; }
float sound_level_rms() { return _rms; }
bool  sound_level_clap(){ bool c = _clap; _clap = false; return c; }
